messages.content:
Candidate Name: {{candidate_name}}
Current Title: {{current_title}}
Years of Experience: {{years_experience}}
Roles Interested In: {{role_interest}}
Cover Note: {{cover_note}}

Extract the following fields:
- skills: array of strings (technical and soft skills identified)
- seniority: one of ["Junior", "Mid", "Senior", "Lead", "Executive"]
- primary_role_type: one of ["Engineering", "Design", "Product", "Marketing", "Operations", "Sales", "Legal", "Finance", "Other"]
- availability_signal: one of ["Immediate", "1 Month", "3 Months", "Unknown"]
- summary: one sentence summary of the candidate profile

config.code:
try {
  const raw = inputData.claude_response;
  const parsed = JSON.parse(raw);
  return {
    skills: Array.isArray(parsed.skills) ? parsed.skills.join(', ') : '',
    seniority: parsed.seniority || 'Unknown',
    primary_role_type: parsed.primary_role_type || 'Other',
    availability_signal: parsed.availability_signal || 'Unknown',
    summary: parsed.summary || '',
    parse_success: 'true'
  };
} catch (e) {
  return {
    skills: '',
    seniority: 'Unknown',
    primary_role_type: 'Other',
    availability_signal: 'Unknown',
    summary: '',
    parse_success: 'false',
    parse_error: e.message
  };
}

const parseOk = inputData.parse_success === 'true';
const isResubmission = inputData.existing_record_id && inputData.existing_record_id.trim() !== '';
return {
  initial_status: parseOk ? 'New' : 'Needs Manual Review',
  is_resubmission: isResubmission ? 'true' : 'false'
};

const noRole = !inputData.open_role_id || inputData.open_role_id.trim() === '';
if (noRole) {
  return { match_score: 0, match_count: 0, is_match: 'false' };
}
const candidateSkills = (inputData.candidate_skills || '').toLowerCase().split(',').map(s => s.trim()).filter(Boolean);
const requiredSkills = (inputData.role_required_skills || '').toLowerCase().split(',').map(s => s.trim()).filter(Boolean);
if (requiredSkills.length === 0) {
  return { match_score: 100, match_count: 0, is_match: 'true' };
}
let matchCount = 0;
for (const skill of requiredSkills) {
  if (candidateSkills.some(cs => cs.includes(skill) || skill.includes(cs))) {
    matchCount++;
  }
}
const matchScore = Math.round((matchCount / requiredSkills.length) * 100);
return {
  match_score: matchScore,
  match_count: matchCount,
  is_match: matchScore >= 40 ? 'true' : 'false'
};

